const STATE_VERSION = 'webcore-boot-sounds-v1';

const EVENTS = [
  { id: 'boot', label: 'boot bloom', color: '#00f5d4' },
  { id: 'login', label: 'login glass', color: '#f15bb5' },
  { id: 'popup', label: 'popup ding', color: '#fee440' },
  { id: 'click', label: 'ui click', color: '#f8f8f8' },
  { id: 'error', label: 'system error', color: '#ff4d6d' },
  { id: 'shutdown', label: 'shutdown veil', color: '#9b5de5' }
];

export default function setup(ctx, prevState) {
  const audio = ctx.audioCtx;
  const dom = ctx.domRoot;
  const matchedState = prevState?.stateVersion === STATE_VERSION;
