    stateVersion: STATE_VERSION,
    enabled: matchedState ? prevState.enabled !== false : true,
    volume: matchedState ? clamp(finite(prevState.volume, 0.48), 0, 0.9) : 0.48,
    density: matchedState ? clamp(finite(prevState.density, 0.52), 0, 1) : 0.52,
    nostalgia: matchedState ? clamp(finite(prevState.nostalgia, 0.68), 0, 1) : 0.68,
    glitch: matchedState ? clamp(finite(prevState.glitch, 0.22), 0, 1) : 0.22,
    echo: matchedState ? clamp(finite(prevState.echo, 0.36), 0, 0.85) : 0.36
  };

  const liveNodes = new Set();
  const cleanupTimers = new Set();
  const listeners = [];
