    setActive('boot');
  };

  const playLogin = (time, velocity = 1) => {
    [76, 83, 88].forEach((midi, index) => {
      makeTone({
        time: time + index * 0.08,
        freq: midiToFreq(midi),
        duration: 0.24,
        gain: velocity * (0.075 - index * 0.011),
        type: 'sine',
        attack: 0.004,
        release: 0.24,
        pan: index === 1 ? 0.36 : -0.22,
        filterFreq: 7200
      });
    });
    setActive('login');
  };

  const playPopup = (time, velocity = 1) => {
    makeTone({ time, freq: midiToFreq(84), duration: 0.11, gain: velocity * 0.105, type: 'triangle', attack: 0.002, release: 0.09, pan: -0.18, filterFreq: 6200 });
    makeTone({ time: time + 0.045, freq: midiToFreq(88), duration: 0.15, gain: velocity * 0.072, type: 'sine', attack: 0.002, release: 0.13, pan: 0.2, filterFreq: 7600 });
    setActive('popup');
  };

  const playClick = (time, velocity = 1) => {
    makeTone({ time, freq: 1500 + state.glitch * 700, duration: 0.018, gain: velocity * 0.045, type: 'square', attack: 0.001, release: 0.015, filterFreq: 3800 + state.nostalgia * 2600 });
    makeNoise({ time, duration: 0.028, gain: velocity * 0.022, freq: 4800, q: 0.7 });
    setActive('click');
  };

  const playError = (time, velocity = 1) => {
    [61, 58].forEach((midi, index) => {
      makeTone({
        time: time + index * 0.095,
        freq: midiToFreq(midi),
        duration: 0.12,
        gain: velocity * 0.13,
        type: 'square',
        attack: 0.002,
        release: 0.07,
        filterFreq: 1700 + state.glitch * 1900,
        bend: 0.985,
        pan: index ? 0.2 : -0.2
      });
    });
    makeNoise({ time, duration: 0.16, gain: velocity * state.glitch * 0.06, type: 'bandpass', freq: 1200, q: 3.5 });
    setActive('error');
  };

  const playShutdown = (time, velocity = 1) => {
    [72, 67, 60].forEach((midi, index) => {
      makeTone({
        time: time + index * 0.02,
        freq: midiToFreq(midi),
        duration: 0.46,
        gain: velocity * (0.075 - index * 0.008),
        type: 'triangle',
        attack: 0.02,
        release: 0.34,
        filterFreq: 3600 - index * 400,
        bend: 0.72,
        pan: (index - 1) * 0.26
      });
    });
    setActive('shutdown');
  };

  const triggerEvent = (id, time, velocity = 1) => {
    if (!state.enabled) return;
    if (id === 'boot') playBoot(time, velocity);
    if (id === 'login') playLogin(time, velocity);
    if (id === 'popup') playPopup(time, velocity);
    if (id === 'click') playClick(time, velocity);
    if (id === 'error') playError(time, velocity);
    if (id === 'shutdown') playShutdown(time, velocity);
  };

  dom.innerHTML = `
    <style>
      .webcore {
        box-sizing: border-box;
        width: 100%;
        height: 100%;
        min-width: 300px;
        min-height: 214px;
        overflow: hidden;
        display: grid;
        grid-template-rows: auto auto 1fr;
        gap: 8px;
        padding: 10px;
        color: #111;
        background:
          linear-gradient(180deg, #f2f2f2 0, #c9c9c9 38%, #9f9f9f 100%);
        border: 2px solid #f8f8f8;
        border-right-color: #4a4a4a;
        border-bottom-color: #4a4a4a;
        border-radius: 2px;
        font: 11px/1.25 ui-monospace, SFMono-Regular, Menlo, Consolas, monospace;
      }
      .titlebar {
        height: 24px;
        min-width: 0;
        display: grid;
        grid-template-columns: minmax(0, 1fr) auto;
        align-items: center;
        gap: 8px;
        padding: 0 5px 0 7px;
        color: #fff;
        background: linear-gradient(90deg, #003f8f, #008080 62%, #f15bb5);
        border: 1px solid #222;
      }
      h1 {
        margin: 0;
        overflow: hidden;
        text-overflow: ellipsis;
        white-space: nowrap;
        font: 700 12px/1 ui-sans-serif, system-ui, sans-serif;
        letter-spacing: 0;
      }
      .buttons {
        display: grid;
        grid-template-columns: repeat(3, 14px);
        gap: 3px;
      }
      .buttons span {
        width: 14px;
        height: 14px;
        box-sizing: border-box;
        background: #d8d8d8;
        border: 1px solid #fff;
        border-right-color: #333;
        border-bottom-color: #333;
      }
      .controls {
        display: grid;
        grid-template-columns: repeat(2, minmax(0, 1fr));
        gap: 6px 9px;
      }
      label {
        min-width: 0;
        display: grid;
        grid-template-columns: 58px minmax(0, 1fr) 27px;
        align-items: center;
        gap: 5px;
      }
      input[type="range"] {
        width: 100%;
        min-width: 0;
        accent-color: #008080;
      }
      button {
        height: 22px;
        padding: 0 8px;
        border: 1px solid #fff;
        border-right-color: #333;
        border-bottom-color: #333;
        border-radius: 2px;
        background: #dedede;
        color: #111;
        font: inherit;
        cursor: pointer;
      }
      button:active {
        border: 1px solid #333;
        border-right-color: #fff;
        border-bottom-color: #fff;
      }
      button.off {
        color: #555;
        background: #b9b9b9;
      }
      .screen {
        min-height: 88px;
        display: grid;
        grid-template-columns: minmax(0, 1fr) 78px;
        gap: 8px;
        padding: 8px;
        background:
          radial-gradient(circle at calc(50% + var(--pulse) * 7%) 42%, var(--active) 0, rgba(255,255,255,0.56) calc(3% + var(--pulse) * 7%), transparent calc(20% + var(--pulse) * 15%)),
          linear-gradient(135deg, #050505, #071717 50%, #19041a);
        border: 1px solid #444;
        border-right-color: #eee;
        border-bottom-color: #eee;
        color: #f8f8f8;
      }
      .status {
        min-width: 0;
        display: grid;
        align-content: end;
        gap: 5px;
      }
      .event {
        min-width: 0;
        overflow: hidden;
        text-overflow: ellipsis;
        white-space: nowrap;
        color: var(--active);
        font: 700 20px/1 ui-sans-serif, system-ui, sans-serif;
        letter-spacing: 0;
        text-shadow: 0 0 calc(6px + var(--pulse) * 18px) var(--active);
      }
      .sub {
        color: #cfcfcf;
        font-size: 10px;
      }
      .stack {
        position: relative;
        min-height: 72px;
      }
      .window {
        position: absolute;
        width: 57px;
        height: 36px;
        box-sizing: border-box;
        border: 1px solid #d9d9d9;
        background: rgba(210, 210, 210, 0.17);
        box-shadow: 0 0 calc(8px + var(--pulse) * 12px) rgba(255, 255, 255, 0.2);
        transform: translateY(calc(var(--pulse) * -4px));
      }
      .window:nth-child(1) { left: 4px; top: 3px; border-top: 5px solid #00f5d4; }
      .window:nth-child(2) { left: 15px; top: 20px; border-top: 5px solid #fee440; }
      .window:nth-child(3) { left: 0; top: 38px; border-top: 5px solid #f15bb5; }
      .steps {
        display: grid;
        grid-template-columns: repeat(16, 1fr);
        gap: 2px;
        grid-column: 1 / -1;
        align-self: end;
      }
      .steps span {
        height: 5px;
        min-width: 0;
        background: rgba(255, 255, 255, 0.22);
      }
      .steps span.on {
        background: var(--active);
        box-shadow: 0 0 8px var(--active);
      }
      @media (max-width: 360px) {
        .controls {
          grid-template-columns: 1fr;
        }
        .event {
          font-size: 17px;
        }
      }
    </style>
    <div class="webcore" style="--pulse:0;--active:#00f5d4">
      <div class="titlebar">
        <h1>WEBCORE BOOT RANDOMIZER</h1>
        <div class="buttons" aria-hidden="true"><span></span><span></span><span></span></div>
      </div>
      <div class="controls">
        <label>volume <input id="volume" type="range" min="0" max="0.9" step="0.01"><span id="volumeVal"></span></label>
        <label>density <input id="density" type="range" min="0" max="1" step="0.01"><span id="densityVal"></span></label>
        <label>nostal <input id="nostalgia" type="range" min="0" max="1" step="0.01"><span id="nostalgiaVal"></span></label>
        <label>glitch <input id="glitch" type="range" min="0" max="1" step="0.01"><span id="glitchVal"></span></label>
        <label>echo <input id="echo" type="range" min="0" max="0.85" step="0.01"><span id="echoVal"></span></label>
        <button id="enabled" type="button"></button>
      </div>
      <div class="screen">
        <div class="status">
          <div id="event" class="event">waiting</div>
          <div id="sub" class="sub">random boot, popup, click, error tones</div>
        </div>
        <div class="stack" aria-hidden="true"><div class="window"></div><div class="window"></div><div class="window"></div></div>
        <div id="steps" class="steps"></div>
      </div>
    </div>
  `;

  const root = dom.querySelector('.webcore');
  const eventEl = dom.querySelector('#event');
  const subEl = dom.querySelector('#sub');
  const enabledButton = dom.querySelector('#enabled');
  const stepWrap = dom.querySelector('#steps');
  const controls = {
    volume: dom.querySelector('#volume'),
    density: dom.querySelector('#density'),
    nostalgia: dom.querySelector('#nostalgia'),
    glitch: dom.querySelector('#glitch'),
    echo: dom.querySelector('#echo')
  };
  const readouts = {
    volume: dom.querySelector('#volumeVal'),
    density: dom.querySelector('#densityVal'),
    nostalgia: dom.querySelector('#nostalgiaVal'),
    glitch: dom.querySelector('#glitchVal'),
    echo: dom.querySelector('#echoVal')
  };
  const stepEls = Array.from({ length: 16 }, () => {
    const el = document.createElement('span');
    stepWrap.appendChild(el);
    return el;
  });

  const renderControls = () => {
    Object.keys(controls).forEach((key) => {
      controls[key].value = String(state[key]);
      readouts[key].textContent = Math.round(state[key] * 100);
    });
    enabledButton.textContent = state.enabled ? 'audio on' : 'muted';
    enabledButton.classList.toggle('off', !state.enabled);
  };

  Object.entries(controls).forEach(([key, inputEl]) => {
    const onInput = () => {
      state[key] = Number(inputEl.value);
      readouts[key].textContent = Math.round(state[key] * 100);
      updateFx();
    };
    inputEl.addEventListener('input', onInput);
    listeners.push([inputEl, 'input', onInput]);
  });

  const onEnabled = () => {
    state.enabled = !state.enabled;
    updateFx();
    renderControls();
  };
  enabledButton.addEventListener('click', onEnabled);
  listeners.push([enabledButton, 'click', onEnabled]);

  renderControls();

  const unsubscribeClock = ctx.clock.onTick(({ step, time }) => {
    lastStep = step % 16;
    if (!state.enabled) return;

    const density = state.density;
    const velocity = 0.78 + randomFor(step, 40) * 0.32;
    const phrase = step % 64;
    const r1 = randomFor(step, 1);
    const r2 = randomFor(step, 2);
    const r3 = randomFor(step, 3);

    if (phrase === 0 && r1 < 0.48 + density * 0.44) {
      triggerEvent('boot', time, velocity);
      return;
    }
    if (phrase === 48 && r1 < 0.18 + density * 0.36) {
      triggerEvent('shutdown', time, velocity * 0.9);
      return;
    }
    if (step % 16 === 8 && r2 < 0.22 + density * 0.48) {
      triggerEvent('login', time, velocity);
      return;
    }
    if (step % 4 === 2 && r1 < 0.08 + density * 0.24) {
      triggerEvent('popup', time, velocity * 0.86);
      return;
    }
    if (step % 8 === 6 && r2 < 0.035 + density * 0.11 + state.glitch * 0.08) {
      triggerEvent('error', time, velocity * 0.82);
      return;
    }
    if (r3 < 0.02 + density * 0.16) {
      triggerEvent('click', time, velocity * 0.75);
    }
  });

  const draw = () => {
    pulse = Math.max(0, pulse * 0.9 - 0.008);
    root.style.setProperty('--pulse', pulse.toFixed(3));
    root.style.setProperty('--active', activeColor);
    eventEl.textContent = activeEvent;
    subEl.textContent = state.enabled ? `step ${lastStep < 0 ? '--' : String(lastStep + 1).padStart(2, '0')} / random webcore audio` : 'muted';
    stepEls.forEach((el, index) => el.classList.toggle('on', index === lastStep));
    raf = requestAnimationFrame(draw);
  };
  raf = requestAnimationFrame(draw);

  return {
    update() {},
    getState() {
      return { ...state };
    },
    destroy() {
      unsubscribeClock();
      cancelAnimationFrame(raf);
      listeners.forEach(([target, type, handler]) => target.removeEventListener(type, handler));
      cleanupTimers.forEach((timer) => clearTimeout(timer));
      cleanupTimers.clear();
      liveNodes.forEach((node) => {
        try {
          if (typeof node.stop === 'function') node.stop();
        } catch (_) {}
        try {
          if (typeof node.disconnect === 'function') node.disconnect();
        } catch (_) {}
      });
      liveNodes.clear();
      [input, dry, delay, feedback, delayTone, wet, compressor, master].forEach((node) => {
        try { node.disconnect(); } catch (_) {}
      });
    }
  };
}
